import numpy as np
from forward import A1, A2, b1

# For direction 0, let's see A1[i,0] and A2[i]
print('Direction 0 analysis:')
for i in range(20):
    if abs(A1[i,0]) > 1e-10:
        t = -b1[i] / A1[i,0]
        # The slope change: 
        # If A1[i,j] > 0: before=0, after=A2[i]*A1[i,j], Δ = A2[i]*A1[i,j]
        # If A1[i,j] < 0: before=A2[i]*A1[i,j], after=0, Δ = -A2[i]*A1[i,j] = A2[i]*|A1[i,j]|
        if A1[i,0] > 0:
            delta = A2[0,i] * A1[i,0]
        else:
            delta = -A2[0,i] * A1[i,0]  # = A2[i]*|A1[i,0]|
        inv = t * delta
        print(f'  Neuron {i}: A1={A1[i,0]:+.6f}, A2={A2[0,i]:+.6f}, t={t:+.8f}, Δ_formula={delta:+.8f}, t*Δ={inv:+.8f}, trueInv={-b1[i]*A2[0,i]:+.8f}')
